<template><div class="page console-page"><header class="page-header"><div><div class="eyebrow">开发者中心</div><h1 class="page-title">可访问服务模型</h1><p class="page-desc">使用真实 Virtual Key 查询网关 <code>/v1/models</code>，结果严格受 Key 和租户范围控制。</p></div></header><section class="card data-surface"><div class="toolbar"><div class="filters developer-key-filter"><input v-model="apiKey" class="input" type="password" autocomplete="off" placeholder="输入真实 Virtual Key"/><input v-model.trim="keyword" class="input" placeholder="筛选模型" @keyup.enter="load"/><button class="btn primary" :disabled="loading" @click="load">查询模型</button></div><span class="table-meta">{{ filtered.length }} 个</span></div><div v-if="error" class="state-panel error-state"><strong>模型查询失败</strong><p>{{ error }}</p><button class="btn" @click="load">重试</button></div><div v-else-if="loading" class="state-panel"><span class="loading-mark"></span><strong>正在按 Key 权限查询网关</strong></div><template v-else><div class="table-wrap"><table class="data-table"><thead><tr><th><button class="sort-button" @click="toggleSort">模型标识 {{ ascending?'↑':'↓' }}</button></th><th>对象类型</th><th>归属</th></tr></thead><tbody><tr v-for="row in paged" :key="row.id"><td><code>{{ row.id }}</code></td><td>{{ row.object }}</td><td>{{ row.owned_by }}</td></tr></tbody></table></div><div v-if="queried&&!filtered.length" class="state-panel empty-state"><strong>当前 Key 没有可访问模型</strong><p>请检查 Key 模型范围、租户可见性、路由和价格是否均已生效。</p></div><div v-if="!queried" class="state-panel empty-state"><strong>请输入 Virtual Key</strong><p>页面不会保存或使用示例密钥。</p></div><footer v-if="filtered.length>size" class="pagination"><button class="btn" :disabled="page===1" @click="page--">上一页</button><span>第 {{ page }} / {{ pageCount }} 页</span><button class="btn" :disabled="page>=pageCount" @click="page++">下一页</button></footer></template></section></div></template>
<script setup lang="ts">import{computed,ref}from'vue';import axios from'axios';import{errorMessage,gatewayBase}from'../api/client';const apiKey=ref(''),keyword=ref(''),models=ref<any[]>([]),loading=ref(false),error=ref(''),queried=ref(false),ascending=ref(true),page=ref(1),size=20;const filtered=computed(()=>models.value.filter(x=>String(x.id).toLowerCase().includes(keyword.value.toLowerCase())).sort((a,b)=>String(a.id).localeCompare(String(b.id))*(ascending.value?1:-1)));const pageCount=computed(()=>Math.max(1,Math.ceil(filtered.value.length/size))),paged=computed(()=>filtered.value.slice((page.value-1)*size,page.value*size));async function load(){queried.value=true;page.value=1;if(!apiKey.value){error.value='请输入真实 Virtual Key';models.value=[];return}loading.value=true;error.value='';try{const response=await axios.get(`${gatewayBase}/v1/models`,{headers:{Authorization:`Bearer ${apiKey.value}`}});models.value=Array.isArray(response.data?.data)?response.data.data:[]}catch(e){error.value=errorMessage(e);models.value=[]}finally{loading.value=false}}function toggleSort(){ascending.value=!ascending.value}</script>
